package main

import (
  "context"
  "fmt"
  "time"
)

var svcXSema = make(chan struct{}, 10) // max 10 concurrent

func callServiceX(ctx context.Context) error {
  select {
  case svcXSema <- struct{}{}:
    defer func() { <-svcXSema }()
    // Simulate work with a timeout-aware context
    select {
    case <-time.After(200 * time.Millisecond):
      return nil
    case <-ctx.Done():
      return ctx.Err()
    }
  case <-ctx.Done():
    return ctx.Err() // bulkhead full or cancelled
  }
}

func main() {
  ctx, cancel := context.WithTimeout(context.Background(), 100*time.Millisecond)
  defer cancel()
  if err := callServiceX(ctx); err != nil {
    fmt.Println("call failed:", err)
  } else {
    fmt.Println("call succeeded")
  }
}
